-- ========================================
-- টেবিল / Table: email_templates
-- তারিখ / Date: 2026-03-07 01:28:41
-- মোড / Mode: Full Export
-- মোট সারি / Total Rows: 7
-- ========================================

CREATE TABLE IF NOT EXISTS `email_templates` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(100) NOT NULL,
  `slug` varchar(100) NOT NULL,
  `subject` varchar(255) NOT NULL,
  `body` longtext NOT NULL,
  `variables` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Available template variables' CHECK (json_valid(`variables`)),
  `description` text DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_by` int(11) DEFAULT NULL,
  `updated_by` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `name` (`name`),
  UNIQUE KEY `slug` (`slug`),
  KEY `created_by` (`created_by`),
  KEY `updated_by` (`updated_by`),
  KEY `idx_slug` (`slug`),
  KEY `idx_is_active` (`is_active`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ডাটা ইনসার্ট / Data Insert

INSERT INTO `email_templates` (`id`, `name`, `slug`, `subject`, `body`, `variables`, `description`, `is_active`, `created_by`, `updated_by`, `created_at`, `updated_at`, `deleted_at`) VALUES ('1', 'Welcome Email', 'welcome_email', 'Welcome to {{APP_NAME}}!', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<title>Welcome</title>\r\n<style>\r\nbody{margin:0;padding:0;background:#f4f6f9;font-family:Arial,sans-serif}\r\n.card{max-width:520px;margin:40px auto;background:#fff;border-radius:10px;box-shadow:0 10px 25px rgba(0,0,0,.08)}\r\n.header{background:#0d6efd;color:#fff;padding:20px;text-align:center;border-radius:10px 10px 0 0}\r\n.content{padding:24px;color:#333;line-height:1.6}\r\n.btn{display:inline-block;background:#0d6efd;color:#fff;text-decoration:none;padding:12px 20px;border-radius:6px;font-weight:bold}\r\n.footer{font-size:12px;color:#777;padding:15px;text-align:center;border-top:1px solid #eee}\r\n</style>\r\n</head>\r\n<body>\r\n\r\n<div class=\"card\">\r\n  <div class=\"header\">\r\n    <h1>Welcome {{USER_NAME}} 🎉</h1>\r\n  </div>\r\n  <div class=\"content\">\r\n    <p>Thank you for joining <strong>{{APP_NAME}}</strong>.</p>\r\n    <p>Your account {{USER_EMAIL}} is ready to use. Please verify your email to get started.</p>\r\n    <p style=\"text-align:center\">\r\n      <a href=\"{{VERIFY_LINK}}\" class=\"btn\">Verify Email</a>\r\n    </p>\r\n  </div>\r\n  <div class=\"footer\">\r\n    © {{APP_NAME}} — Secure & Reliable\r\n  </div>\r\n</div>\r\n\r\n</body>\r\n</html>', '{\"APP_NAME\":\"\",\"USER_NAME\":\"\",\"USER_EMAIL\":\"\",\"VERIFY_LINK\":\"\"}', 'Sent to new users after registration', '1', NULL, '1', '2026-01-15 20:14:16', '2026-01-16 15:45:03', NULL);
INSERT INTO `email_templates` (`id`, `name`, `slug`, `subject`, `body`, `variables`, `description`, `is_active`, `created_by`, `updated_by`, `created_at`, `updated_at`, `deleted_at`) VALUES ('2', 'Email Verification', 'email_verification', 'Verify Your Email Address', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<title>Email Verification</title>\r\n<style>\r\nbody{margin:0;padding:0;background:#f4f6f9;font-family:Arial,sans-serif}\r\n.card{max-width:520px;margin:40px auto;background:#fff;border-radius:10px;box-shadow:0 10px 25px rgba(0,0,0,.08)}\r\n.header{background:#198754;color:#fff;padding:20px;text-align:center}\r\n.content{padding:24px;color:#333}\r\n.btn{display:inline-block;background:#198754;color:#fff;text-decoration:none;padding:12px 20px;border-radius:6px;font-weight:bold}\r\n.note{font-size:13px;color:#666;margin-top:15px}\r\n</style>\r\n</head>\r\n<body>\r\n\r\n<div class=\"card\">\r\n  <div class=\"header\">\r\n    <h1>Email Verification Required - {{APP_NAME}}</h1>\r\n  </div>\r\n  <div class=\"content\">\r\n    <p>Hi {{USER_NAME}},</p>\r\n    <p>Please verify your email address <strong>{{USER_EMAIL}}</strong> by clicking the button below.</p>\r\n\r\n    <p style=\"text-align:center\">\r\n      <a href=\"{{VERIFY_LINK}}\" class=\"btn\">Verify Email</a>\r\n    </p>\r\n\r\n    <p class=\"note\">⏳ This link expires in {{EXPIRY_TIME}}.</p>\r\n  </div>\r\n</div>\r\n\r\n</body>\r\n</html>', '{\"APP_NAME\":\"\",\"USER_NAME\":\"\",\"USER_EMAIL\":\"\",\"VERIFY_LINK\":\"\",\"EXPIRY_TIME\":\"\"}', 'Email verification link', '1', NULL, '1', '2026-01-15 20:14:16', '2026-01-16 15:45:03', NULL);
INSERT INTO `email_templates` (`id`, `name`, `slug`, `subject`, `body`, `variables`, `description`, `is_active`, `created_by`, `updated_by`, `created_at`, `updated_at`, `deleted_at`) VALUES ('3', 'Password Reset', 'password_reset', 'Reset Your Password', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<title>Password Reset</title>\r\n<style>\r\nbody{margin:0;padding:0;background:#f4f6f9;font-family:Arial,sans-serif}\r\n.card{max-width:520px;margin:40px auto;background:#fff;border-radius:10px;box-shadow:0 10px 25px rgba(0,0,0,.08)}\r\n.header{background:#dc3545;color:#fff;padding:20px;text-align:center}\r\n.content{padding:24px;color:#333}\r\n.btn{display:inline-block;background:#dc3545;color:#fff;text-decoration:none;padding:12px 20px;border-radius:6px;font-weight:bold}\r\n.warning{font-size:13px;color:#666;margin-top:15px}\r\n</style>\r\n</head>\r\n<body>\r\n\r\n<div class=\"card\">\r\n  <div class=\"header\">\r\n    <h1>{{APP_NAME}} - Password Reset Request</h1>\r\n  </div>\r\n  <div class=\"content\">\r\n    <p>Hi {{USER_NAME}},</p>\r\n    <p>We received a request to reset your password for account {{USER_EMAIL}}.</p>\r\n\r\n    <p style=\"text-align:center\">\r\n      <a href=\"{{RESET_LINK}}\" class=\"btn\">Reset Password</a>\r\n    </p>\r\n\r\n    <p class=\"warning\">\r\n      ⏳ Link expires in: {{EXPIRY_TIME}}<br/>\r\n      ⚠️ If you did not request this, please ignore this email.\r\n    </p>\r\n  </div>\r\n</div>\r\n\r\n</body>\r\n</html>', '{\"APP_NAME\":\"\",\"USER_NAME\":\"\",\"USER_EMAIL\":\"\",\"RESET_LINK\":\"\",\"EXPIRY_TIME\":\"\"}', 'Password reset token link', '1', NULL, '1', '2026-01-15 20:14:16', '2026-01-16 15:45:03', NULL);
INSERT INTO `email_templates` (`id`, `name`, `slug`, `subject`, `body`, `variables`, `description`, `is_active`, `created_by`, `updated_by`, `created_at`, `updated_at`, `deleted_at`) VALUES ('4', 'Account Locked', 'account_locked', 'Your Account Has Been Locked', '<!DOCTYPE html>\r\n<html lang=\"en\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<title>Account Security Alert</title>\r\n<style>\r\n    body {\r\n        margin: 0;\r\n        padding: 0;\r\n        background-color: #f4f6f9;\r\n        font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, Arial, sans-serif;\r\n    }\r\n\r\n    .alert-wrapper {\r\n        max-width: 520px;\r\n        margin: 40px auto;\r\n        background: #ffffff;\r\n        border-radius: 12px;\r\n        box-shadow: 0 10px 30px rgba(0, 0, 0, 0.08);\r\n        overflow: hidden;\r\n    }\r\n\r\n    .alert-header {\r\n        background: linear-gradient(135deg, #dc3545, #b02a37);\r\n        color: #ffffff;\r\n        padding: 20px 24px;\r\n        text-align: center;\r\n    }\r\n\r\n    .alert-header h1 {\r\n        margin: 0;\r\n        font-size: 22px;\r\n        font-weight: 600;\r\n        letter-spacing: 0.3px;\r\n    }\r\n\r\n    .alert-body {\r\n        padding: 24px;\r\n        color: #333333;\r\n        line-height: 1.6;\r\n    }\r\n\r\n    .alert-body p {\r\n        margin: 0 0 16px;\r\n        font-size: 15px;\r\n    }\r\n\r\n    .alert-body strong {\r\n        color: #dc3545;\r\n    }\r\n\r\n    .alert-actions {\r\n        text-align: center;\r\n        padding: 0 24px 24px;\r\n    }\r\n\r\n    .btn-support {\r\n        display: inline-block;\r\n        background: #dc3545;\r\n        color: #ffffff;\r\n        text-decoration: none;\r\n        padding: 12px 22px;\r\n        border-radius: 8px;\r\n        font-size: 14px;\r\n        font-weight: 600;\r\n        transition: background 0.3s ease;\r\n    }\r\n\r\n    .btn-support:hover {\r\n        background: #b02a37;\r\n    }\r\n\r\n    .alert-footer {\r\n        background: #f8f9fb;\r\n        padding: 14px 24px;\r\n        font-size: 12px;\r\n        color: #777777;\r\n        text-align: center;\r\n        border-top: 1px solid #e5e7eb;\r\n    }\r\n</style>\r\n</head>\r\n<body>\r\n\r\n<div class=\"alert-wrapper\">\r\n    <div class=\"alert-header\">\r\n        <h1>🔒 {{APP_NAME}} - Account Security Alert</h1>\r\n    </div>\r\n\r\n    <div class=\"alert-body\">\r\n        <p>Hi {{USER_NAME}},</p>\r\n        <p>\r\n            We detected <strong>multiple failed login attempts</strong> on your account {{USER_EMAIL}}.\r\n            For your protection, your account has been temporarily locked.\r\n        </p>\r\n        <p>\r\n            Please contact our support team at <strong>{{SUPPORT_EMAIL}}</strong> to verify your identity and regain access.\r\n        </p>\r\n    </div>\r\n\r\n    <div class=\"alert-actions\">\r\n        <a href=\"mailto:{{SUPPORT_EMAIL}}\" class=\"btn-support\">Contact Support</a>\r\n    </div>\r\n\r\n    <div class=\"alert-footer\">\r\n        If this wasn\'t you, please contact support immediately.\r\n    </div>\r\n</div>\r\n\r\n</body>\r\n</html>', '{\"APP_NAME\":\"\",\"USER_NAME\":\"\",\"USER_EMAIL\":\"\",\"SUPPORT_EMAIL\":\"\"}', 'Account locked notification', '1', NULL, '1', '2026-01-15 20:14:16', '2026-01-16 15:45:03', NULL);
INSERT INTO `email_templates` (`id`, `name`, `slug`, `subject`, `body`, `variables`, `description`, `is_active`, `created_by`, `updated_by`, `created_at`, `updated_at`, `deleted_at`) VALUES ('5', 'New User Registration', 'admin_new_user', 'New User Registration - {{USER_NAME}}', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<title>New User Registration</title>\r\n<style>\r\nbody{margin:0;padding:0;background:#f4f6f9;font-family:Arial,sans-serif}\r\n.card{max-width:520px;margin:40px auto;background:#fff;border-radius:10px;box-shadow:0 10px 25px rgba(0,0,0,.08)}\r\n.header{background:#6f42c1;color:#fff;padding:20px;text-align:center}\r\n.content{padding:24px;color:#333}\r\n.info{background:#f8f9fa;padding:15px;border-radius:6px;font-size:14px}\r\n.btn{display:inline-block;background:#6f42c1;color:#fff;text-decoration:none;padding:12px 20px;border-radius:6px;font-weight:bold;margin-top:15px}\r\n</style>\r\n</head>\r\n<body>\r\n\r\n<div class=\"card\">\r\n  <div class=\"header\">\r\n    <h1>New User Registered - {{APP_NAME}}</h1>\r\n  </div>\r\n\r\n  <div class=\"content\">\r\n    <div class=\"info\">\r\n      <p><strong>Name:</strong> {{USER_NAME}}</p>\r\n      <p><strong>Email:</strong> {{USER_EMAIL}}</p>\r\n      <p><strong>Registration Time:</strong> {{REGISTRATION_TIME}}</p>\r\n    </div>\r\n\r\n    <p style=\"text-align:center\">\r\n      <a href=\"{{ADMIN_LINK}}\" class=\"btn\">View User in Admin Panel</a>\r\n    </p>\r\n  </div>\r\n</div>\r\n\r\n</body>\r\n</html>', '{\"APP_NAME\":\"\",\"USER_NAME\":\"\",\"USER_EMAIL\":\"\",\"REGISTRATION_TIME\":\"\",\"ADMIN_LINK\":\"\"}', 'Admin notification for new registrations', '1', NULL, '1', '2026-01-15 20:14:16', '2026-01-16 15:45:03', NULL);
INSERT INTO `email_templates` (`id`, `name`, `slug`, `subject`, `body`, `variables`, `description`, `is_active`, `created_by`, `updated_by`, `created_at`, `updated_at`, `deleted_at`) VALUES ('6', 'Newsletter Welcome', 'newsletter_welcome', 'স্বাগতম আমাদের নিউজলেটারে!', '<!DOCTYPE html>\r\n<html lang=\"bn\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<title>Newsletter Welcome</title>\r\n<style>\r\nbody{\r\n  margin:0;\r\n  padding:0;\r\n  background:#f4f6f9;\r\n  font-family:Arial, sans-serif;\r\n}\r\n.card{\r\n  max-width:520px;\r\n  margin:40px auto;\r\n  background:#ffffff;\r\n  border-radius:10px;\r\n  box-shadow:0 10px 25px rgba(0,0,0,.08);\r\n}\r\n.header{\r\n  background:#0dcaf0;\r\n  color:#ffffff;\r\n  padding:20px;\r\n  text-align:center;\r\n  border-radius:10px 10px 0 0;\r\n}\r\n.content{\r\n  padding:24px;\r\n  color:#333333;\r\n  line-height:1.6;\r\n  font-size:15px;\r\n}\r\n.footer{\r\n  font-size:12px;\r\n  color:#777;\r\n  padding:15px;\r\n  text-align:center;\r\n  border-top:1px solid #eee;\r\n}\r\n</style>\r\n</head>\r\n<body>\r\n\r\n<div class=\"card\">\r\n  <div class=\"header\">\r\n    <h1>📩 স্বাগতম আমাদের নিউজলেটারে!</h1>\r\n  </div>\r\n\r\n  <div class=\"content\">\r\n    <p>হ্যালো {{SUBSCRIBER_NAME}},</p>\r\n\r\n    <p>\r\n      আপনি সফলভাবে <strong>{{APP_NAME}}</strong> এর নিউজলেটার সাবস্ক্রাইব করেছেন।\r\n    </p>\r\n\r\n    <p>\r\n      এখন থেকে আপনি নিয়মিত আপডেট, অফার এবং বিশেষ ঘোষণা পেতে থাকবেন।\r\n    </p>\r\n\r\n    <p>ধন্যবাদ আমাদের সাথে থাকার জন্য! 💙</p>\r\n  </div>\r\n\r\n  <div class=\"footer\">\r\n    © {{APP_NAME}} — All rights reserved\r\n  </div>\r\n</div>\r\n\r\n</body>\r\n</html>', '{\"APP_NAME\":\"\",\"SUBSCRIBER_NAME\":\"\"}', 'Welcome email sent after newsletter subscription', '1', NULL, '1', '2026-02-01 04:47:40', '2026-02-01 04:47:40', NULL);
INSERT INTO `email_templates` (`id`, `name`, `slug`, `subject`, `body`, `variables`, `description`, `is_active`, `created_by`, `updated_by`, `created_at`, `updated_at`, `deleted_at`) VALUES ('7', 'Contact Acknowledgment', 'contact_acknowledgment', '📨 We’ve received your message – {{APP_NAME}}', '<!DOCTYPE html>\r\n<html lang=\"bn\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<title>Contact Acknowledgment</title>\r\n<style>\r\nbody{\r\n  margin:0;\r\n  padding:0;\r\n  background:#f4f6f9;\r\n  font-family:Arial, sans-serif;\r\n}\r\n.card{\r\n  max-width:520px;\r\n  margin:40px auto;\r\n  background:#ffffff;\r\n  border-radius:10px;\r\n  box-shadow:0 10px 25px rgba(0,0,0,.08);\r\n}\r\n.header{\r\n  background:#0d6efd;\r\n  color:#ffffff;\r\n  padding:20px;\r\n  text-align:center;\r\n  border-radius:10px 10px 0 0;\r\n}\r\n.content{\r\n  padding:24px;\r\n  color:#333333;\r\n  line-height:1.6;\r\n  font-size:15px;\r\n}\r\n.footer{\r\n  font-size:12px;\r\n  color:#777;\r\n  padding:15px;\r\n  text-align:center;\r\n  border-top:1px solid #eee;\r\n}\r\n</style>\r\n</head>\r\n<body>\r\n\r\n<div class=\"card\">\r\n  <div class=\"header\">\r\n    <h1>📨 আপনার বার্তা পেয়েছি!</h1>\r\n  </div>\r\n\r\n  <div class=\"content\">\r\n    <p>হ্যালো {{SENDER_NAME}},</p>\r\n\r\n    <p>\r\n      <strong>{{APP_NAME}}</strong>–এর সাথে যোগাযোগ করার জন্য ধন্যবাদ।\r\n      আমরা আপনার বার্তাটি সফলভাবে গ্রহণ করেছি।\r\n    </p>\r\n\r\n    <p>\r\n      আমাদের টিম খুব শিগগিরই আপনার বার্তাটি পর্যালোচনা করবে এবং প্রয়োজনে\r\n      আপনার সাথে যোগাযোগ করবে।\r\n    </p>\r\n\r\n    <p>\r\n      এর মধ্যে যদি অতিরিক্ত কোনো তথ্য দিতে চান, তাহলে এই ইমেইলের রিপ্লাই দিতে পারেন।\r\n    </p>\r\n\r\n    <p>ধন্যবাদ ও শুভেচ্ছা! 💙</p>\r\n  </div>\r\n\r\n  <div class=\"footer\">\r\n    © {{APP_NAME}} — All rights reserved\r\n  </div>\r\n</div>\r\n\r\n</body>\r\n</html>', '{\"SENDER_NAME\":\"\",\"APP_NAME\":\"\"}', NULL, '1', NULL, '1', '2026-02-03 11:35:20', '2026-02-03 17:35:19', NULL);
